class Solution(object):
    def maximumTotalCost(self, nums):
        # dp[0] = max total if current element is NOT negated (starts new subarray or continues)
        # dp[1] = max total if current element IS negated (inside a subarray, odd position)
        # First element is always +nums[0]
        n = len(nums)
        if n == 1:
            return nums[0]
        dp0 = nums[0]  # current index not negated
        dp1 = float('-inf')  # current index negated (impossible for index 0)
        for i in range(1, n):
            new_dp0 = max(dp0, dp1) + nums[i]  # this element is positive (start new or continue even pos)
            new_dp1 = dp0 - nums[i]            # this element is negated (must follow non-negated)
            dp0, dp1 = new_dp0, new_dp1
        return max(dp0, dp1)
